/* ── Quick lookup by name ── */
function nexusFind(name){
  if(!name) return null;
  const n = name.toLowerCase().replace(/[^a-z0-9]/g,'');
  let hit = NEXUS_DB.find(p => p.name === name);
  if(hit) return hit;
  hit = NEXUS_DB.find(p => p.name.toLowerCase().replace(/[^a-z0-9]/g,'') === n);
  if(hit) return hit;
  // word-overlap
  const words = name.toLowerCase().split(/\s+/).filter(w=>w.length>2);
  let best=null, bestScore=0;
  NEXUS_DB.forEach(p=>{
    const pw = p.name.toLowerCase().split(/\s+/);
    const score = words.filter(w=>pw.some(x=>x.includes(w)||w.includes(x))).length;
    if(score>bestScore){bestScore=score;best=p;}
  });
  return bestScore>=2 ? best : null;
}

